import { useState, useEffect } from "react";
import "./AddPatient.css";

const countryCityMap = {
  India: ["Delhi", "Mumbai", "Bangalore", "Chennai"],
  UAE: ["Dubai", "Abu Dhabi"],
  USA: ["New York", "Chicago"]
};

const countryCodes = [
  { code: "+91", name: "India" },
  { code: "+971", name: "UAE" },
  { code: "+1", name: "USA" }
];

export default function AddPatient() {
  const [dob, setDob] = useState("");
  const [age, setAge] = useState("");

  const [country, setCountry] = useState("");
  const [cityList, setCityList] = useState([]);

  const [photo, setPhoto] = useState(null);

  const [patientIdNumber, setPatientIdNumber] = useState("");
  const [emergencyIdNumber, setEmergencyIdNumber] = useState("");

  const [patientIdFile, setPatientIdFile] = useState(null);
  const [emergencyIdFile, setEmergencyIdFile] = useState(null);

  const [countryCode, setCountryCode] = useState("+91");
  const [emgCountryCode, setEmgCountryCode] = useState("+91");

  // ================= AGE AUTO =================
  useEffect(() => {
    if (!dob) return;
    const birth = new Date(dob);
    const today = new Date();
    let a = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) a--;
    setAge(a);
  }, [dob]);

  const handleCountryChange = (value) => {
    setCountry(value);
    setCityList(countryCityMap[value] || []);
  };

  return (
    <div className="patient-page">

      {/* ================= HEADER ================= */}
      <div className="patient-header">
        <div>
          <h2>Patient Registration</h2>
          <p>HL7 • ADT A04</p>
        </div>

        {/* PHOTO */}
        <div className="photo-box">
          {photo ? <img src={photo} alt="patient" /> : <span>Upload Photo</span>}

          <input
            type="file"
            accept="image/*"
            capture="environment"
            onChange={(e) =>
              setPhoto(URL.createObjectURL(e.target.files[0]))
            }
          />
        </div>
      </div>

      <div className="patient-card">

        {/* ================= PATIENT INFO ================= */}
        <section>
          <h3>Patient Information</h3>

          <div className="grid">
            <div>
              <label>Medical Record Number (MRN)</label>
              <input placeholder="MRN12345" />
            </div>

            <div className="span-2">
              <label>Display Name</label>
              <input placeholder="John A Doe" />
            </div>
          </div>

          <div className="grid">
            <div>
              <label>Date of Birth</label>
              <input
                type="date"
                value={dob}
                onChange={(e) => setDob(e.target.value)}
              />
            </div>

            <div>
              <label>Age</label>
              <input value={age} readOnly />
            </div>

            <div>
              <label>Gender</label>
              <select>
                <option>Male</option>
                <option>Female</option>
              </select>
            </div>

            <div>
              <label>Marital Status</label>
              <select>
                <option>Single</option>
                <option>Married</option>
              </select>
            </div>
          </div>
        </section>

        {/* ================= CONTACT ================= */}
        <section>
          <h3>Contact Details</h3>

          <div className="grid">
            <div>
              <label>Country</label>
              <select
                value={country}
                onChange={(e) => handleCountryChange(e.target.value)}
              >
                <option value="">Select Country</option>
                {Object.keys(countryCityMap).map((c) => (
                  <option key={c}>{c}</option>
                ))}
              </select>
            </div>

            <div>
              <label>City</label>
              <select>
                <option>Select City</option>
                {cityList.map((c) => (
                  <option key={c}>{c}</option>
                ))}
              </select>
            </div>

            <div>
              <label>Mobile</label>
              <input />
            </div>
          </div>
        </section>

        {/* ================= PATIENT ID ================= */}
        <section>
          <h3>Patient Identification</h3>

          <div className="grid">

            <div>
              <label>ID Type</label>
              <select>
                <option>Aadhaar</option>
                <option>PAN</option>
                <option>Passport</option>
              </select>
            </div>

            <div>
              <label>ID Number</label>
              <input
                value={patientIdNumber}
                onChange={(e) => setPatientIdNumber(e.target.value)}
                placeholder="Enter manually OR scan"
              />
            </div>

            <div>
              <label>Scan ID</label>
              <input
                type="file"
                accept="image/*"
                capture="environment"
                className="scan-btn"
                onChange={(e) => setPatientIdFile(e.target.files[0])}
              />
            </div>

          </div>
        </section>

        {/* ================= EMERGENCY ================= */}
        <section>
          <h3>Emergency Contact</h3>

          <div className="grid">

            <div>
              <label>ID Number</label>
              <input
                value={emergencyIdNumber}
                onChange={(e) => setEmergencyIdNumber(e.target.value)}
                placeholder="Manual or Scan"
              />
            </div>

            <div>
              <label>Scan ID</label>
              <input
                type="file"
                accept="image/*"
                capture="environment"
                className="scan-btn"
                onChange={(e) => setEmergencyIdFile(e.target.files[0])}
              />
            </div>

          </div>
        </section>

        <div className="actions">
          <button className="submit">Register Patient</button>
        </div>

      </div>
    </div>
  );
}
